#!/usr/bin/env rust-script

//! Comprehensive benchmarks for Sprint 7 - stats-rs vs R performance comparison
//! Tests all major functionality: OLS, GLM, Lasso, Ridge

use std::fs::File;
use std::io::Write;
use std::process::Command;
use std::time::Instant;

use ndarray::{Array1, Array2};
use stats_models::{Fit, Lm, Glm, Lasso, Ridge, Gaussian, Poisson};
use rand::{Rng, SeedableRng};
use rand::rngs::StdRng;
use rand_distr::{Distribution, Normal, Poisson as PoissonDist};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== stats-rs vs R Comprehensive Performance Benchmarks ===");
    println!("Sprint 7: Targeting aggressive performance goals from CLAUDE.md");
    println!();

    // Run all benchmarks
    benchmark_ols()?;
    benchmark_glm_gaussian()?;
    benchmark_glm_poisson()?;
    benchmark_lasso()?;
    benchmark_ridge()?;

    println!("\n=== Benchmark Summary ===");
    println!("Target performance requirements (from CLAUDE.md):");
    println!("- Linear Models: ≥2x faster than R's lm()");
    println!("- GLM: ≥5x faster than R's glm()");
    println!("- Regularization: Match or exceed glmnet performance");

    Ok(())
}

fn benchmark_ols() -> Result<(), Box<dyn std::error::Error>> {
    println!("\n--- Benchmarking OLS (Linear Models) ---");
    println!("Target: ≥2x faster than R's lm()");

    let sizes = vec![(100, 5), (1000, 10), (10000, 20), (100000, 50)];

    for (n_obs, n_vars) in sizes {
        println!("\nDataset size: {} observations, {} variables", n_obs, n_vars);

        // Generate data
        let mut rng = StdRng::seed_from_u64(42);
        let mut x_data = Vec::with_capacity(n_obs * n_vars);
        let mut y_data = Vec::with_capacity(n_obs);

        // Generate predictors and response
        for _ in 0..n_obs {
            let mut row_sum = 0.0;
            for j in 0..n_vars {
                let val = if j == 0 { 1.0 } else { rng.gen_range(-5.0..5.0) };
                x_data.push(val);
                row_sum += val * (j as f64 * 0.5);
            }
            y_data.push(row_sum + rng.gen_range(-0.5..0.5));
        }

        // Benchmark stats-rs
        let start = Instant::now();
        let _fit = Lm::fit(&x_data, &y_data, n_obs, n_vars)?;
        let rust_time = start.elapsed();

        // Benchmark R (if available)
        let r_time = benchmark_r_lm(n_obs, n_vars, &x_data, &y_data)?;

        // Report results
        println!("  stats-rs: {:?}", rust_time);
        if let Some(r_duration) = r_time {
            println!("  R lm():   {:?}", r_duration);
            let speedup = r_duration.as_secs_f64() / rust_time.as_secs_f64();
            println!("  Speedup:  {:.2}x {}", speedup, 
                if speedup >= 2.0 { "✅" } else { "❌" });
        }
    }

    Ok(())
}

fn benchmark_glm_gaussian() -> Result<(), Box<dyn std::error::Error>> {
    println!("\n--- Benchmarking GLM (Gaussian family) ---");
    println!("Target: ≥5x faster than R's glm()");

    let sizes = vec![(100, 5), (1000, 10), (10000, 20)];

    for (n_obs, n_vars) in sizes {
        println!("\nDataset size: {} observations, {} variables", n_obs, n_vars);

        // Generate data
        let mut rng = StdRng::seed_from_u64(42);
        let normal = Normal::new(0.0, 1.0)?;

        let mut x_matrix = Array2::zeros((n_obs, n_vars));
        let mut y_array = Array1::zeros(n_obs);

        for i in 0..n_obs {
            x_matrix[[i, 0]] = 1.0; // intercept
            let mut linear_pred = 2.0; // intercept value

            for j in 1..n_vars {
                let val = normal.sample(&mut rng);
                x_matrix[[i, j]] = val;
                linear_pred += val * (j as f64 * 0.3);
            }

            y_array[i] = linear_pred + normal.sample(&mut rng) * 0.5;
        }

        // Benchmark stats-rs
        let start = Instant::now();
        let _fit = Glm::fit_ndarray(x_matrix.view(), y_array.view(), Gaussian, None, None)?;
        let rust_time = start.elapsed();

        // Benchmark R (if available)
        let r_time = benchmark_r_glm_gaussian(n_obs, n_vars, &x_matrix, &y_array)?;

        // Report results
        println!("  stats-rs: {:?}", rust_time);
        if let Some(r_duration) = r_time {
            println!("  R glm():  {:?}", r_duration);
            let speedup = r_duration.as_secs_f64() / rust_time.as_secs_f64();
            println!("  Speedup:  {:.2}x {}", speedup, 
                if speedup >= 5.0 { "✅" } else { "❌" });
        }
    }

    Ok(())
}

fn benchmark_glm_poisson() -> Result<(), Box<dyn std::error::Error>> {
    println!("\n--- Benchmarking GLM (Poisson family) ---");
    println!("Target: ≥5x faster than R's glm()");

    let sizes = vec![(100, 5), (1000, 10), (10000, 20)];

    for (n_obs, n_vars) in sizes {
        println!("\nDataset size: {} observations, {} variables", n_obs, n_vars);

        // Generate count data
        let mut rng = StdRng::seed_from_u64(42);
        let mut x_matrix = Array2::zeros((n_obs, n_vars));
        let mut y_array = Array1::zeros(n_obs);

        for i in 0..n_obs {
            x_matrix[[i, 0]] = 1.0; // intercept
            let mut log_rate = 1.0; // log(base rate)

            for j in 1..n_vars {
                let val = rng.gen_range(-2.0..2.0);
                x_matrix[[i, j]] = val;
                log_rate += val * (j as f64 * 0.2);
            }

