//! Sprint 7 Performance Analysis
//! Quick performance test comparing stats-rs to target goals

use std::time::Instant;
use ndarray::{Array1, Array2};
use rand::{Rng, SeedableRng};
use rand::rngs::StdRng;
use stats_models::{Fit, Lm, Glm, Lasso, Ridge, Gaussian};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== Sprint 7 Performance Analysis ===");
    println!("Testing against CLAUDE.md performance targets\n");

    // Test 1: Linear Models (target: ≥2x faster than R)
    test_lm_performance()?;

    // Test 2: GLM (target: ≥5x faster than R) 
    test_glm_performance()?;

    // Test 3: Regularized models (target: match/exceed glmnet)
    test_regularized_performance()?;

    Ok(())
}

fn test_lm_performance() -> Result<(), Box<dyn std::error::Error>> {
    println!("--- Linear Models (OLS) Performance ---");
    println!("Target: ≥2x faster than R's lm()\n");

    let mut rng = StdRng::seed_from_u64(42);

    for (n_obs, n_vars) in &[(1000, 10), (10000, 20), (50000, 30)] {
        print!("Dataset: {} obs x {} vars ... ", n_obs, n_vars);

        // Generate data
        let mut x_data = Vec::with_capacity(n_obs * n_vars);
        let mut y_data = Vec::with_capacity(*n_obs);

        for _ in 0..*n_obs {
            let mut row_sum = 0.0;
            for j in 0..*n_vars {
                let val = if j == 0 { 1.0 } else { rng.gen_range(-5.0..5.0) };
                x_data.push(val);
                row_sum += val * (j as f64 * 0.5);
            }
            y_data.push(row_sum + rng.gen_range(-0.5..0.5));
        }

        // Warm up
        let _ = Lm::fit(&x_data, &y_data, *n_obs, *n_vars)?;

        // Time it
        let start = Instant::now();
        let fit = Lm::fit(&x_data, &y_data, *n_obs, *n_vars)?;
        let elapsed = start.elapsed();

        println!("{:?} (R² = {:.4})", elapsed, fit.summary().r_squared);
    }

    println!();
    Ok(())
}

fn test_glm_performance() -> Result<(), Box<dyn std::error::Error>> {
    println!("--- GLM (Gaussian) Performance ---");
    println!("Target: ≥5x faster than R's glm()\n");

    let mut rng = StdRng::seed_from_u64(42);

    for (n_obs, n_vars) in &[(1000, 10), (5000, 20), (10000, 30)] {
        print!("Dataset: {} obs x {} vars ... ", n_obs, n_vars);

        // Generate data
        let mut x_matrix = Array2::zeros((*n_obs, *n_vars));
        let mut y_array = Array1::zeros(*n_obs);

        for i in 0..*n_obs {
            x_matrix[[i, 0]] = 1.0;
            let mut linear_pred = 2.0;

            for j in 1..*n_vars {
                let val = rng.gen_range(-2.0..2.0);
                x_matrix[[i, j]] = val;
                linear_pred += val * (j as f64 * 0.3);
            }

            y_array[i] = linear_pred + rng.gen_range(-0.5..0.5);
        }

        // Warm up
        let _ = Glm::fit_ndarray(x_matrix.view(), y_array.view(), Gaussian, None, None)?;

        // Time it
        let start = Instant::now();
        let fit = Glm::fit_ndarray(x_matrix.view(), y_array.view(), Gaussian, None, None)?;
        let elapsed = start.elapsed();

        let deviance_explained = 1.0 - fit.deviance / fit.null_deviance;
        println!("{:?} (Deviance explained = {:.4})", elapsed, deviance_explained);
    }

    println!();
    Ok(())
}

fn test_regularized_performance() -> Result<(), Box<dyn std::error::Error>> {
    println!("--- Regularized Models Performance ---");
    println!("Target: Match or exceed glmnet\n");

    let mut rng = StdRng::seed_from_u64(42);
    let lambda = 0.1;

    // Test high-dimensional sparse data
    for (n_obs, n_vars) in &[(500, 100), (1000, 200), (2000, 500)] {
        println!("Dataset: {} obs x {} vars (high-dimensional)", n_obs, n_vars);

        // Generate sparse data
        let mut x_matrix = Array2::zeros((*n_obs, *n_vars));
        let mut y_array = Array1::zeros(*n_obs);

        // Only 10% of coefficients are non-zero
        let n_active = n_vars / 10;
        let mut true_coefs = vec![0.0; *n_vars];
        for i in 0..n_active {
            true_coefs[i * 10] = rng.gen_range(1.0..3.0) * if rng.gen_bool(0.5) { 1.0 } else { -1.0 };
        }

        for i in 0..*n_obs {
            let mut y = 0.0;
            for j in 0..*n_vars {
                let val = rng.gen_range(-1.0..1.0);
                x_matrix[[i, j]] = val;
                y += val * true_coefs[j];
            }
            y_array[i] = y + rng.gen_range(-0.1..0.1);
        }

        // Test Lasso
        print!("  Lasso: ");
        let start = Instant::now();
        let lasso_fit = Lasso::fit(x_matrix.view(), y_array.view(), lambda, None)?;
        let lasso_time = start.elapsed();

        let n_nonzero = lasso_fit.coefficients().iter().filter(|&&c| c.abs() > 1e-10).count();
        println!("{:?}, {} non-zero coefs ({:.1}% sparse)", 
            lasso_time, n_nonzero, (1.0 - n_nonzero as f64 / n_vars as f64) * 100.0);

        // Test Ridge  
        print!("  Ridge: ");
        let start = Instant::now();
        let ridge_fit = Ridge::fit(x_matrix.view(), y_array.view(), lambda, None)?;
        let ridge_time = start.elapsed();

        println!("{:?}, R² = {:.4}", ridge_time, ridge_fit.summary().r_squared);
    }

    println!();
    Ok(())
}

