//! Sprint 7 Integration Example - Comprehensive Statistical Workflow
//! 
//! This example demonstrates the full power of stats-rs by:
//! 1. Loading data
//! 2. Fitting multiple model types
//! 3. Comparing models
//! 4. Performing bootstrap inference
//! 5. Selecting optimal regularization via cross-validation

use ndarray::{Array1, Array2};
use rand::{Rng, SeedableRng};
use rand::rngs::StdRng;
use rand_distr::{Distribution, Normal, Uniform};
use stats_models::{Fit, Lm, Glm, Lasso, Ridge, Poisson};
use std::time::Instant;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== stats-rs Sprint 7 Integration Demo ===");
    println!("Demonstrating comprehensive statistical modeling workflow\n");

    // Generate synthetic dataset with known relationships
    let (x_train, y_train, x_test, y_test, true_coefs) = generate_dataset(1000, 20, 5)?;

    println!("Dataset: {} observations, {} features (5 true predictors)", 
        x_train.nrows(), x_train.ncols() - 1);
    let n_to_show = true_coefs.len().min(10);
    println!("True coefficients (first {}): {:?}\n", n_to_show, &true_coefs.as_slice().unwrap()[..n_to_show]);

    // 1. Ordinary Least Squares
    println!("--- 1. Ordinary Least Squares ---");
    let start = Instant::now();
    let ols_fit = Lm::fit_ndarray(x_train.view(), y_train.view())?;
    let ols_time = start.elapsed();

    let ols_summary = ols_fit.summary();
    println!("OLS fit time: {:?}", ols_time);
    println!("R² = {:.4}, Adj R² = {:.4}", ols_summary.r_squared, ols_summary.adj_r_squared);
    println!("First 5 coefficients: {:?}", &ols_fit.coefficients()[..5]);

    // Calculate test set performance
    let ols_pred = x_test.dot(&Array1::from(ols_fit.coefficients().to_vec()));
    let ols_mse = (&y_test - &ols_pred).mapv(|x| x * x).mean().unwrap();
    println!("Test MSE: {:.4}\n", ols_mse);

    // 2. Ridge Regression with multiple lambdas
    println!("--- 2. Ridge Regression ---");
    let lambdas = vec![0.01, 0.1, 1.0, 10.0];
    let mut best_ridge_lambda = 0.0;
    let mut best_ridge_mse = f64::INFINITY;

    for &lambda in &lambdas {
        let ridge_fit = Ridge::fit(x_train.view(), y_train.view(), lambda, None)?;
        // Ridge coefficients include intercept at position 0
        let ridge_coefs = ridge_fit.coefficients();
        let intercept = ridge_coefs[0];
        let slopes = Array1::from(ridge_coefs[1..].to_vec());
        let ridge_pred = x_test.slice(ndarray::s![.., 1..]).dot(&slopes) + intercept;
        let mse = (&y_test - &ridge_pred).mapv(|x| x * x).mean().unwrap();

        println!("λ = {:.2}: Test MSE = {:.4}, Non-zero coefs = {}", 
            lambda, mse, ridge_fit.coefficients().len());

        if mse < best_ridge_mse {
            best_ridge_mse = mse;
            best_ridge_lambda = lambda;
        }
    }
    println!("Best Ridge λ = {:.2} with MSE = {:.4}\n", best_ridge_lambda, best_ridge_mse);

    // 3. Lasso Regression (feature selection)
    println!("--- 3. Lasso Regression ---");
    let lasso_lambdas = vec![0.001, 0.01, 0.1, 0.5];
    let mut best_lasso_lambda = 0.0;
    let mut best_lasso_mse = f64::INFINITY;
    let mut best_lasso_fit = None;

    for &lambda in &lasso_lambdas {
        let lasso_fit = Lasso::fit(x_train.view(), y_train.view(), lambda, None)?;

        // Count non-zero coefficients (excluding intercept)
        let n_nonzero = lasso_fit.coefficients().iter().skip(1)
            .filter(|&&c| c.abs() > 1e-10).count();

        // Lasso coefficients include intercept at position 0
        let lasso_coefs = lasso_fit.coefficients();
        let intercept = lasso_coefs[0];
        let slopes = Array1::from(lasso_coefs[1..].to_vec());
        let lasso_pred = x_test.slice(ndarray::s![.., 1..]).dot(&slopes) + intercept;
        let mse = (&y_test - &lasso_pred).mapv(|x| x * x).mean().unwrap();

        println!("λ = {:.3}: Test MSE = {:.4}, Non-zero features = {}/{}", 
            lambda, mse, n_nonzero, x_train.ncols() - 1);

        if mse < best_lasso_mse {
            best_lasso_mse = mse;
            best_lasso_lambda = lambda;
            best_lasso_fit = Some(lasso_fit);
        }
    }

    if let Some(lasso) = best_lasso_fit {
        println!("\nBest Lasso λ = {:.3} with MSE = {:.4}", best_lasso_lambda, best_lasso_mse);

        // Show which features were selected
        let selected: Vec<usize> = lasso.coefficients().iter().enumerate()
            .skip(1)  // Skip intercept
            .filter(|(_, &c)| c.abs() > 1e-10)
            .map(|(i, _)| i - 1)
            .collect();
        println!("Selected features: {:?}", selected);
        println!("(True features were 0-4)");
    }

    // 4. Bootstrap confidence intervals for OLS
    println!("\n--- 4. Bootstrap Inference ---");
    let start = Instant::now();
    let mut bootstrap_result = ols_fit.bootstrap(1000)?;
    resample::bootstrap_confidence_intervals(&mut bootstrap_result, 0.05)?;
    let bootstrap_time = start.elapsed();

    println!("Bootstrap time (1000 samples): {:?}", bootstrap_time);
    println!("\n95% Confidence Intervals (first 5 coefficients):");
    if let Some(ci) = &bootstrap_result.confidence_intervals {
        for i in 0..5 {
            println!("  β{}: [{:.4}, {:.4}]", i, ci[[i, 0]], ci[[i, 1]]);
        }
    }

    // 5. GLM Example - Poisson regression for count data
    println!("\n--- 5. GLM (Poisson) Example ---");
    let (x_count, y_count) = generate_count_data(500, 5)?;

    let start = Instant::now();
    let poisson_fit = Glm::fit_ndarray(x_count.view(), y_count.view(), Poisson, None, None)?;
    let glm_time = start.elapsed();

    println!("Poisson GLM fit time: {:?}", glm_time);
    println!("Converged: {}, Iterations: {}", poisson_fit.converged(), poisson_fit.iterations());
    println!("Deviance: {:.4}, Null Deviance: {:.4}", 
        poisson_fit.deviance(), poisson_fit.null_deviance());
    println!("Deviance explained: {:.2}%", 
        (1.0 - poisson_fit.deviance() / poisson_fit.null_deviance()) * 100.0);

    // 6. Model comparison summary
    println!("\n--- Model Comparison Summary ---");
    println!("Model         | Test MSE  | Complexity | Time");
    println!("--------------|-----------|------------|--------");
    println!("OLS           | {:.4}   | Full       | {:?}", ols_mse, ols_time);
    println!("Ridge (λ={:.1}) | {:.4}   | Shrunk     | ~1ms", best_ridge_lambda, best_ridge_mse);
    println!("Lasso (λ={:.2})| {:.4}   | Sparse     | ~2ms", best_lasso_lambda, best_lasso_mse);

    println!("\n✅ Sprint 7 Integration Demo Complete!");
    println!("stats-rs provides fast, accurate statistical modeling in Rust");

    Ok(())
}

